import{bQ as a,aL as e,u as i,G as h}from"./chunks/framework.D06dwy5q.js";const r=JSON.parse('{"title":"01｜Shell 脚本是什么、为什么要写","description":"","frontmatter":{},"headers":[],"relativePath":"02.Shell脚本/01-Shell脚本是什么为什么要写.md","filePath":"02.Shell脚本/01-Shell脚本是什么为什么要写.md","lastUpdated":null}'),t={name:"02.Shell脚本/01-Shell脚本是什么为什么要写.md"};function l(n,s,p,d,o,c){return e(),i("div",null,[...s[0]||(s[0]=[h(`<h1 id="_01-shell-脚本是什么、为什么要写" tabindex="-1">01｜Shell 脚本是什么、为什么要写 <a class="header-anchor" href="#_01-shell-脚本是什么、为什么要写" aria-label="Permalink to &quot;01｜Shell 脚本是什么、为什么要写&quot;">​</a></h1><p>Linux 基础系列里学的都是一条一条的命令——敲一条 <code>df -h</code> 看磁盘，敲一条 <code>free -h</code> 看内存，敲一条 <code>ps</code> 看进程。</p><p>但真实运维不是敲一条命令就完事。排查磁盘满了，要敲一串：先 <code>df -h</code> 定位哪个盘满了，再 <code>du -sh /*</code> 找大目录，再 <code>find</code> 找大文件，最后清理。每次磁盘告警都重复敲这一串，漏一步或敲错一步就可能出事。十台机器查一遍就是十次重复。</p><p>Shell 脚本解决的就是这个——把一串命令写进文件，一次执行、可重复、可审计。</p><h2 id="一、脚本和单条命令的区别" tabindex="-1">一、脚本和单条命令的区别 <a class="header-anchor" href="#一、脚本和单条命令的区别" aria-label="Permalink to &quot;一、脚本和单条命令的区别&quot;">​</a></h2><p>把命令写进文件，让系统按顺序执行，这个文件就是脚本。最简单的一个：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># check-disk.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">du</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -hr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -5</span></span></code></pre></div><p>把这个文件跑一下：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check-disk.sh</span></span></code></pre></div><p>效果和手动敲这两条命令一样。区别是：以后每次磁盘告警，直接 <code>bash check-disk.sh</code> 一条命令搞定，不用记一串，也不会漏步。机器多了还能配着 SSH 批量跑，十台机器一个循环搞定。</p><p>脚本还能加判断——只有磁盘超过 80% 才告警、清理前先确认文件能不能删、失败时退出并报错。这些靠单条命令做不到。</p><h2 id="二、shell-和-python-的分工" tabindex="-1">二、Shell 和 Python 的分工 <a class="header-anchor" href="#二、shell-和-python-的分工" aria-label="Permalink to &quot;二、Shell 和 Python 的分工&quot;">​</a></h2><p>写自动化可以用 Shell，也可以用 Python。各有适用场景。</p><p>Shell 脚本的强项是<strong>串联系统命令</strong>：调 <code>df</code>、<code>grep</code>、<code>awk</code>、<code>curl</code>，把它们用管道和重定向串起来处理文本和系统状态。Linux 自带就能跑，不用装任何运行时。运维里大量的&quot;查个状态、清个日志、批量跑个命令&quot;用 Shell 写最直接。</p><p>Python 的强项是<strong>复杂逻辑和数据结构</strong>：要解析 JSON、调 API、处理复杂对象、做数学计算、写大型程序。Python 标准库丰富，但语法和命令行工具的结合不如 Shell 直接。</p><p>判断标准很简单：<strong>主要是调系统命令处理文本，用 Shell；主要是逻辑运算和数据处理，用 Python</strong>。一个磁盘巡检脚本用 Shell 写十来行，用 Python 反而啰嗦；一个调 API 拉数据生成报表的任务，用 Python 清晰，用 Shell 写会很难维护。</p><p>本系列讲 Shell 脚本。Python 脚本有专门的系列。</p><h2 id="三、第一个脚本" tabindex="-1">三、第一个脚本 <a class="header-anchor" href="#三、第一个脚本" aria-label="Permalink to &quot;三、第一个脚本&quot;">​</a></h2><p>写一个能跑的脚本，走一遍完整流程。先建文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.sh</span></span></code></pre></div><p>内容：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/env bash</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello shell&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;当前用户: $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whoami</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;当前目录: $(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span></span></code></pre></div><p>第一行 <code>#!/usr/bin/env bash</code> 是 shebang，告诉系统用 bash 执行这个文件。后面三行是命令，<code>$(...)</code> 是命令替换——先跑里面的命令，把输出塞回原位置。</p><p>执行它：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.sh</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hello shell</span></span>
<span class="line"><span>当前用户: root</span></span>
<span class="line"><span>当前目录: /root</span></span></code></pre></div><p>脚本跑起来了。但每次都要写 <code>bash hello.sh</code> 不方便，想直接 <code>./hello.sh</code> 跑，得加执行权限：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./hello.sh</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hello shell</span></span>
<span class="line"><span>当前用户: root</span></span>
<span class="line"><span>当前目录: /root</span></span></code></pre></div><p>两种执行方式的区别：<code>bash hello.sh</code> 是显式用 bash 解释器跑文件，不需要执行权限；<code>./hello.sh</code> 是把文件当可执行程序跑，靠 shebang 找解释器，需要执行权限。生产脚本一般加执行权限，方便直接 <code>./</code> 跑或放进 PATH 里当命令用。</p><h2 id="四、shebang-的写法" tabindex="-1">四、shebang 的写法 <a class="header-anchor" href="#四、shebang-的写法" aria-label="Permalink to &quot;四、shebang 的写法&quot;">​</a></h2><p>shebang（<code>#!</code>）写在脚本第一行，指定解释器。两种写法：</p><table tabindex="0"><thead><tr><th>写法</th><th>特点</th></tr></thead><tbody><tr><td><code>#!/usr/bin/env bash</code></td><td>从 PATH 找 bash，可移植性好</td></tr><tr><td><code>#!/bin/bash</code></td><td>路径明确，但某些发行版 bash 不在 <code>/bin/bash</code></td></tr></tbody></table><p>推荐 <code>#!/usr/bin/env bash</code>——可移植性好。注意别误写成 <code>#!/bin/sh</code>：<code>sh</code> 在不同系统上指向不同（有的是 bash 的兼容模式，有的是 dash），行为可能不一致。脚本里用了 bash 特性（数组、<code>[[ ]]</code> 等），shebang 就得写 bash，不能写 sh。</p><h2 id="五、脚本为什么比命令行强" tabindex="-1">五、脚本为什么比命令行强 <a class="header-anchor" href="#五、脚本为什么比命令行强" aria-label="Permalink to &quot;五、脚本为什么比命令行强&quot;">​</a></h2><p>到这里，脚本能跑、能串命令、能加执行权限。但脚本真正比命令行强的地方还没体现——它能加判断、循环、错误处理。</p><p>后面的篇章依次讲这些：变量和引号、条件判断、循环、函数，把脚本从&quot;一串命令的记录&quot;变成&quot;能做决策的程序&quot;。本系列的目标是让读者能写出可用的运维脚本——巡检、备份、批量操作、初始化，这些日常重复的事交给脚本自动跑。</p>`,37)])])}const b=a(t,[["render",l]]);export{r as __pageData,b as default};
